def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        ratio = item / capacity
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio < 0:
            priorities[i] = np.inf
            continue
        if ratio > 10:
            penalty = 0
            for k in range(1, 6):
                penalty += (ratio ** (2 * k)) / ((k ** 2) * 3)
            priorities[i] = ratio ** 4 + penalty + (np.sin(ratio) * 5)
        elif 1 < ratio <= 10:
            base = np.log1p(ratio)
            penalty_sum = 0
            for p in range(1, 5):
                penalty_sum += (-1)**p * (ratio ** p) / p
            corrections = 0
            for q in range(1, 6):
                if q % 2 == 0:
                    corrections += np.exp(-q * ratio) / q
                else:
                    corrections -= np.exp(-q * ratio) / q
            priorities[i] = abs(base * penalty_sum) + corrections * 10
        elif 0 < ratio <= 1:
            series_sum = 0
            for j in range(1, 10):
                term = ((-1)**(j+1)) * (ratio ** j) / j
                if j % 3 == 0:
                    term *= 2
                series_sum += term
            weight = 0
            if ratio < 0.25:
                weight = 20
            elif ratio < 0.5:
                weight = 15
            elif ratio < 0.75:
                weight = 10
            else:
                weight = 5
            extra_bonus = 0
            for m in range(1, 5):
                extra_bonus += (ratio ** (m*m)) / (m + 1)
            priorities[i] = abs(series_sum) * weight + extra_bonus
        else:
            if item == 0:
                priorities[i] = 0
            else:
                temp_score = 0
                for r in range(1, 7):
                    if r == 3 or r ==5:
                        continue
                    temp_score += (ratio ** r) / r * ((-1)**r)
                priorities[i] = abs(temp_score) + np.sqrt(abs(ratio))
        if priorities[i] != np.inf and priorities[i] < 1e-6:
            priorities[i] = 1e-6
        if capacity > 0 and item > 0 and ratio != np.inf:
            adjust_factor = np.tanh(capacity / (item + 1e-9)) * 2
            priorities[i] *= adjust_factor
    return priorities
